mapper.insert:

    SELECT 'MENU_' || LPAD((COALESCE(MAX(CAST(SUBSTRING(MENU_CD, 6) AS INTEGER)), 0) + 1)::TEXT, 3, '0')
    FROM DOCS_MENU;


INSERT INTO DOCS_MENU(
    MENU_CD, PARENT_MENU_CD, MENU_NM, MENU_LEVEL, MENU_TYPE, MENU_URL, SORT_SEQ, TREE_TYPE, DEL_YN, USE_YN, ROLE_CD, AUTH_SITE, MENU_ICON
)
VALUES(
    #{menuCd}, #{parentMenuCd}, #{menuNm}, #{menuLevel}, #{menuType}, #{menuUrl},
    (SELECT COALESCE(MAX(SORT_SEQ), 0) + 1 FROM DOCS_MENU), #{treeType}, 'N', #{useYn}, 'ROLE_' || #{menuCd}, #{authSite}, #{menuIcon}
)

mapper.update:
UPDATE DOCS_MENU
SET DEL_YN = 'Y'
WHERE MENU_CD = #{menuCd}

UPDATE DOCS_MENU

    SORT_SEQ = #{sortSeq},
    PARENT_MENU_CD = #{parent},

        MENU_TYPE = #{menuType},


        TREE_TYPE = #{treeType}


WHERE MENU_CD = #{id}
